import{_ as p,o as a,c as e,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"面灵气","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/4.综合类/面灵气.md","filePath":"4.资源分区/1.血统与训练/4.综合类/面灵气.md"}'),n={name:"4.资源分区/1.血统与训练/4.综合类/面灵气.md"};function o(d,b,l,_,i,c){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"面灵气",tabindex:"-1"},[t("面灵气 "),r("a",{class:"header-anchor",href:"#面灵气","aria-label":'Permalink to "面灵气"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),s('<h1 id="面灵气-1" tabindex="-1">面灵气 <a class="header-anchor" href="#面灵气-1" aria-label="Permalink to &quot;面灵气&quot;">​</a></h1><p>面灵气</p><p>圣德太子时<br> 命秦川胜制百面<br> 栩栩如生之面<br> 必川胜之巧夺天工也<br> 于梦中思及此<br> 画图百器徒然袋/卷之下<br> 鸟山石燕/天明三年</p><p>D+600<br> 面具本身就包含着某种灵力，旧面具放置很长时间就会变成付丧神，白天只是普通面具，晚上就会从墙上跑出去，悄无声息的活动。</p><p>付丧神：<br> 又名“九十九神”或“九九神”，日本文化中的鬼神概念，类似于中国的“”，指器物放置不理100年，吸收天地精华、积聚怨念或感受佛性、灵力而得到灵魂化成精怪。</p><p>你开启能量池：妖力（风度+耐力）</p><p>作为付丧神，面具才是你的本体，而人身只是外在表现的姿态。从现在起，你无需饮食，也无需休息</p><p>暗黑能乐：<br> 能是予人感情的演艺<br> 但妖怪的能可以夺取人的感情<br> 这被称作暗黑能乐<br> 当然，这大概只是天狗胡乱编纂的<br> 你获得了一种新的攻击方式，以能乐表演的姿势飞出灵气发起攻击，攻击鉴定为【风度+表达+专业：能乐+辅助专业：乐理学】，攻击距离为15m，伤害性质为纯能量</p><p>表情丰富的扑克脸<br> 秦心是猿乐之祖 秦河胜使用的面具历经漫长的时间后化作的妖怪。<br> 她的每个面具都代表固定的感情，戴上面具后感情就会变化。<br> 你可以从以下三种代表不同情感的的面具中选其一获取，必须在购买时选择，或是购买后支付D+500获得其他两种面具，并将其佩戴在自己的面部，你的脸部将不再有表情变化。</p><p>姥面（属于忧面），能剧中姥面对应老年女性，反映其年老后的烦恼忧愁。当你佩戴忧面具时，你的攻击将附带1点沮丧点数。<br> 小面（属于喜面）：能剧中小面对应年轻女性，反映其活泼和纯真。当你佩戴喜面具时，你将获得【快速医疗1】（医疗点12）。<br> 般若面（属于怒面）：能剧中般若面对应怨灵、恶鬼，故事中常常是因嫉妒、嗔怒化作厉鬼的女性。当你佩戴怒面具时，你的攻击鉴定将获得1点附加成功加值。</p><p>C+1200<br> 猿乐之祖 秦河胜使用的面具历经漫长的时间后化作<br> 的妖怪。<br> 每个面具都代表固定的感情，戴上面具后感情就会变化。<br> 感情也会影响到在附近的人。<br> 面具的数量为六十六个。<br> 虽然每个都有着固定的感情，不过因为实在是很多，因此平时似乎只会<br> 使用喜怒哀乐的面具而已。</p><p>升级-暗黑能乐<br> 舞踏者表演时涂抹白粉，身穿奇装异服，肢体动作扭曲而激烈，显得怪诞狰狞。<br> 其表演主旨为反映人原始的痛苦和纯粹的感情、思考生命的意义等。<br> 你现在更加熟练地掌握了这一种表演技巧，即使不看绘卷，也能表演出相应的能乐，你的攻击鉴定变为【风度+表达+专业：能乐+辅助专业：舞蹈（表达）】</p><p>升级-表情丰富的扑克脸<br> 她能将感情车转轮换，但是自身却始终是面无表情，这便是她无法保持自我的原因。<br> 你可以选择一种面具的效果获得提升，同时可以选择支付C+1000获得其他两种面具效果的提升。如果你拥有其他面具，那么你可以通过一个自由动作进行切换，但切换面具便意味着情感的变化，并且无论如何每轮只能切换一次。</p><p>姥面（属于忧面）：当你佩戴忧面具时，满溢的忧郁令你的攻击附带2点不可豁免的沮丧点数。<br> 小面（属于喜面）：当你佩戴喜面具时，满溢的喜悦令你在D级时获得的快速医疗提升传奇风度点，医疗点提升传奇风度*12。<br> 般若面（属于怒面）：当你佩戴喜面具时，满溢的愤怒令你的表达检定的加骰提升一级，至多为8加骰。</p><p>她在被指出这个原因后，便决定踏上向人类和妖怪学习表情的旅途。<br> 每经过一影片，你的表达鉴定就获得1DP 的士气加值。</p><p>B+2400<br> 实际上，她在稳定的时候基本不会流露出自己的感情。她对于什么事都不感兴趣，在有必要使用面具的时候以外只会悄悄地作为一个付丧神。<br> 因此，也有人说她在暴走的时候显得更有人性一些。</p><p>变幻自在的感情移入：<br> 能乐的表演，面具的切换便意味着情绪的转换，而情绪的转换也会导致转换后的情绪更加激烈。每轮一次，你在切换面具时，你根据切换前的面具和切换后的面具的不同，将会在一轮内产生不同的效果：<br> 忧面-喜面：每轮仅限一次，你在进行攻击检定时可以重掷一次，取其中较高的一次进行结算，该效果持续一轮<br> 忧面-怒面：你的攻击额外附带B级的重伤效果，持续一轮<br> 喜面-忧面：本次攻击将额外附带造成伤害出目的沮丧不良点数，正常豁免。<br> 喜面-怒面：你的攻击将附带【湮灭】特性，持续一轮。<br> 怒面-喜面：指定一名触及范围内的单位，给予其【全遮蔽】效果，同时你获得1点临时生命和1点遮蔽防御，持续一轮，临时生命无法重复获得，除非进入了下个场景。<br> 怒面-忧面：持续一轮，你的攻击命中时，对方进行意志豁免，若失败，则对方陷入B级心灵来源的混乱效果。</p><p>在购买时你只能选择以上三种面具切换的效果，令这三种效果在你切换对应类型的面具时生效，你可以额外花费xp来解锁其他类型的切换面具效果，每6xp可以额外解锁一项切换效果。</p><p>面具收集者<br> 一组情绪面具需要你同时拥有【喜】、【怒】、【忧】C级及以上的每种情绪面具各一个。举例而言，你同时拥有了C级别的【姥面】、【小面】、【般若面】这三种面具，就代表你拥有了一组情绪面具。本资源下技能树的其他C级及以上的面具同样可作为满足情绪面具的条件<br> 你每拥有一组情绪面具，你在攻击上就额外获得传奇风度*3点武器伤害。</p><p>A+4800<br> 心戴上任何一个面具后不仅自身会产生这个面具对应的感情，还具有将这种感情向周围众人传播的能力。人类形态基本是张无表情的脸并且也基本不流露感情，但感情本身还是有的，也会通过戴上自己的喜怒哀乐面具来表达出来。</p><p>凭依「喜怒哀乐附体」：<br> 以自身为中心炸裂感情的波动对应着释放的感情，会对敌人的感情产生影响，令敌人的情绪变得不稳定<br> 当你佩戴不同面具时，你的攻击将额外附带不同效果。</p><p>以忧面释放的感情波动，令对手惶恐并远离。当你的攻击命中时，对方进行意志豁免，成功数为你造成的伤害值，若失败，则陷入A级心灵来源的惊惧效果，效果持续到你的下回合开始。</p><p>以喜面释放的感情波动，令对手在原地发笑。的攻击命中时，对方进行意志豁免，成功数为你造成的伤害值，若失败，则陷入A级心灵来源的混乱效果，效果持续到你的下回合开始。</p><p>以怒面释放的感情波动，令对手发怒并迫近。的攻击命中时，对方进行意志豁免，成功数为你造成的伤害值，若失败，则陷入A级心灵来源的胁迫效果，效果持续到你的下回合开始。</p><p>战栗吧！噩梦的能面女<br> 我漂亮吗？<br> 她想将自己彻底代入裂口女这个角色。<br> 自心底想要代入角色的结果，就是她内心的裂<br> 口女开始分离独立，最后竟产生了全新的灵异珠，<br> 这件事谁都没有注意到<br> 灵异攻击「美学的反击技」，是一回合只能用一次的对攻击过来的对手进行反击的万能当身技，你每轮开始时会获得8AP，仅能用于使用本技能树下的能力，若你没有使用这些ap且你当轮具有额外的标准动作转化次数，可以在回合外受到攻击时，用反射动作调用这8AP转化为标准动作对敌人使用本资源技能树下招式进行一次攻击，通过该方式进行的攻击具有打断性。</p><p>假面舞会：<br> 能乐的表演，每一次面具的切换便是一个高潮，现在你每次切换面具时，你的演出导致的影响范围都会扩大，你的表达检定将获得2DP的士气加值以及1点附加成功的加值，以及【破甲5】【高速5】【威猛5】，持续一轮，不可叠加。</p><p>技能树</p><p>吼怒的妖狐面：<br> D+500<br> 描述：戴上狐面扑向对手的突进技能，面具的灵气化作牙咬住对手，在很广的范围里以横扫的方式将其嚼碎<br> 动作：标准动作<br> 消耗：2点妖力<br> 距离：锥形范围7.5M<br> 效果：立刻切换面具为狐面（属于怒面），你的本次攻击获得2点速度加值和【高速5】，对锥形范围内所有敌人造成伤害。</p><p>忧叹的长壁面：<br> D+500<br> 描述：将有攻击能力的面具撒向四周，怀有敌意者接近时面具会作出反应对其发动攻击。<br> 动作：标准<br> 消耗：1点妖力<br> 距离：15m<br> 效果：立刻切换面具为长壁面（属于忧面），抛出面具撒向四周，对射程内的单一目标进行一次伤害，本次伤害附带C级的措手不及效果以及1点附加成功的加值。</p><p>欢喜的狮子面<br> D+500<br> 描述：取出狮子面具，向着对手从口中豪爽地喷出火焰，被狮子咬到是非常吉利的事情，但如果被烧了会怎么样呢？<br> 动作：标准<br> 消耗：2点妖力<br> 距离：30m<br> 效果：立刻切换面具为狮子面（属于喜面），你本次攻击的伤害类型转变为火焰伤害，同时附带7点燃烧点数与1点攻击上的附加成功，正常豁免。</p><p>怒声的大蜘蛛面<br> C+1000<br> 描述：从土蜘蛛的面具中放出丝线束缚对手，在丝线相连的期间，向后冲刺可以拖拽对手，再次使用技能丝线会断掉，但会把对手击飞到眼前。<br> 动作：标准<br> 消耗：6点妖力<br> 距离：50米<br> 效果：立刻切换面具为大蜘蛛面（属于怒面）<br> 使得你攻击的时候，面具会释放出蛛丝束缚对手，使得你的攻击伤害转化为纠缠不良点数，正常豁免。你也可以选择在直接将丝线断开，目标以反射豁免，若失败则在一轮内对目标额外造成B级的击飞效果，持续一轮。</p><p>忧心的鬼婆面<br> C+1000<br> 描述：向任意的方向释放面具令其待命，在有面具待命的状态下，这个技能会变成叫回面具的动作，面具会攻击着路线上的对手回到手边。<br> 动作：标准<br> 消耗：6点妖力<br> 范围：圆形20米，以自身为中心。<br> 效果：立刻切换面具为鬼婆面（属于忧面）释放大量面具在周围，自身可以在任意时间收回这些面具，对范围内所有单位造成一次伤害，这次伤害获得3DP的士气加值和自身血统等级/1点附加成功。</p><p>狂喜的火男面<br> C+1000<br> 描述：戴上火男面具拿起扇子表演舞蹈，从面具和心洋溢出来的喜悦的感情，化作火焰撒向周围<br> 动作：标准<br> 消耗：6点妖力<br> 范围：圆形15米，以自身为中心。<br> 效果：立刻切换面具为火男面（属于喜面），你本次攻击转化为对周围圆形范围内所有敌人造成伤害，伤害类型转变为火焰伤害，同时附带1点士气加值和13点燃烧点数，正常豁免。</p><p>愤怒的忌狼之面<br> B+2000<br> 描述：放任感情，任由面具扑向对手的突进技能，这张符卡宣言后，随着心的感情切换灵气会增强，同时使用时的性能会得到强化<br> 动作：迅捷动作<br> 消耗：10点妖力<br> 距离：-<br> 效果：立刻切换面具为忌狼之面（属于怒面），你可以在移动中进行攻击，这次攻击获得【8加骰】，若已经拥有【8加骰】则变成+5DP+2附加成功。<br> 同时在本次战斗中，你每切换过一次面具，便使得攻击额外获得1点附加成功的加值，上限为你的传奇决心*2个。以上效果全部持续一轮。</p><p>忧面「杞人忧地」<br> B+2000<br> 描述：将感情的面具投向对手，以其为中心用灵气的奔流将对手打飞的大招，面具会依照心的意念正确地追踪对手，无论对手在哪里都能予以狙击，但相反地心自身会变得毫无防备<br> 动作：整轮<br> 消耗：5点妖力<br> 距离：15+（传奇风度*20米）<br> 效果：将面具投向对手，随后以目标所在位置为圆心，对半径30m内所有敌方单位造成伤害。以及附带B级的击飞效果，并附带等同伤害出目的心灵来源的沮丧点数，意志豁免。<br> 本次攻击会临时降低你的防御，如同冲锋一样计算降低的基础防御和加减值。</p><p>假面丧心舞 暗黑能乐<br> A+4000<br> 描述：召唤大量面具遮黑场景，以能乐表演的姿势发起攻击，有墨水挥洒的效果。<br> 动作：标准<br> 消耗：14点妖力<br> 射程：15+（传奇风度*20）米<br> 效果：你召唤大量面具将场景遮黑，使得自身敏感范围内变为B级困难地形，自身本轮内攻击检定的成功数检定翻倍，被命中的那个单位需进行一次意志豁免对抗攻击成功数，失败则进入A级心灵来源的支配效果，其将无法指定我方单位进行攻击，这个效果持续一轮。<br> 本场战斗内每切换过一次面具，则使得本次攻击附带2DP的士气加值，上限为传奇风度*2点。</p><p>刀<br> D+500<br> 武器伤害6L<br> 【长柄武器】【破甲1】【高速1】【法破】<br> 描述：日本长柄武器的一种，江户时代以后，作为女性的武器被使用，不过在这里，它更像是能乐表演时的一种道具。<br> 能乐表演：虽然作为武器，但在你的手里，她更像是一种能乐的表演道具，你使用暗黑能乐进行检定时将加上本武器的伤害与特性。</p><p>希望之面：<br> 500<br> 一副以丰聪耳神子的脸为蓝本所制作的面具，本来心的各个感情之间保持着平衡，十分稳定，但是当失去其中一个面具之后原本感情具有的力量就会互相干涉，导致暴走，虽然最后神子给心制作了一个新的希望之面，但心认为新的希望之面太完美会担心自己失去独立的自我，但在最后藏的教导下，心学会了将新希望之面融入自我的方法。<br> 希望之面：<br> 持有该奇物时，所有的感情维持着平衡。由于该面具象征着希望的感情，即使在绝望之中，仍会残有一丝希望，你的基因锁检定结果获得1点加值。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',40)])])}const m=p(n,[["render",o]]);export{D as __pageData,m as default};
